//! Score blocks: modular, derive-generated scoring fields.
//!
//! A *score* belongs to a *family*; a family is one file that owns its whole
//! lifecycle — compute-from-inputs, parquet projection (`columns`), and the
//! two-lane ML projections (`linear_features`/`nonlinear_features` = values,
//! `linear_feature_names`/`nonlinear_feature_names` = names). Adding a score to
//! an existing family touches only that file, and forgetting a projection is
//! structurally impossible: all bodies are generated by walking the same field
//! list that defines the struct (see `#[derive(ScoreBlock)]` in
//! `timsseek_macros`), so a partial emission is unrepresentable. Feature
//! *values* are per-record ([`FrameSink`]); feature *names* are a property of
//! the set, built once ([`NameSink`]). The heavy apex-stage families
//! ([`apex_features`], [`split_product`]) keep their compute here too, leaning
//! on the shared numeric primitives in `crate::scoring::apex_dsp`.
//!
//! `#[derive(ScoreBlock)]` handles both scalar and array (`[f32; N]`) fields,
//! so the array families [`ion_errors::IonErrors`] /
//! [`relative_intensities::RelativeIntensities`] are derive-generated too
//! (names `{field}_{i}` from the field + count). Hand-written exceptions that
//! still emit through the same sinks, with compute in-file:
//! - [`identity::Identity`] — irreducibly mixed-dtype.
//! - the conditional, features-only [`sequence_counts`] block.
//!
//! The remaining blocks — including the output-only
//! [`result_meta::ResultMeta`] — are generated by `#[derive(ScoreBlock)]`.

use arrow::array::*;
use arrow::datatypes::*;
use std::sync::Arc;

pub mod apex_features;
pub mod counts;
pub mod derived;
pub mod frame;
pub mod identity;
pub mod intensities;
pub mod ion_errors;
pub mod lazy;
pub mod mobility;
pub mod primary;
pub mod relative_intensities;
pub mod result_meta;
pub mod rt;
pub mod sequence_counts;
pub mod split_product;

pub use frame::{
    FeatFrame,
    FrameSink,
};

// ---------------------------------------------------------------------------
// Trait
// ---------------------------------------------------------------------------

/// A family of scores that projects itself into the two output surfaces.
///
/// `columns` emits the raw stored value at its original dtype (the Parquet
/// projection). Array fields fan out to one column per element, named
/// `{field}_{i}`. The lane methods (`linear_features`/`nonlinear_features`)
/// emit the ML projection, which may apply `#[feat(..)]` transforms and fan a
/// single field out to several features; this is the live path the
/// `rescore`/`rescore_lda` consumers read via [`FeatFrame`].
///
/// `columns` is the only method every block must provide; the schema + lane
/// methods are defaulted to no-ops for blocks that don't participate in a
/// given lane (e.g. `sequence_counts` has no linear lane).
///
/// `features` (LEGACY, value-only — no matching name walk) is kept only
/// because [`crate::ml::cv::FeatureLike::as_feature`] must stay implemented
/// for `CrossValidatedScorer<CompetedCandidate>`'s trait bound, which a
/// test-only ctor (`CrossValidatedScorer::new_from_shuffled`) still exercises.
/// Defaulted no-op; only [`identity::Identity`] overrides it with a real impl.
pub trait ScoreBlock {
    fn columns(&self, out: &mut ColSink);

    /// Parquet-adjacent schema (dtype/nullability only, no data) for the same
    /// fields `columns` emits. Defaulted no-op until a block migrates.
    fn column_schema(_out: &mut SchemaSink) {}
    /// This block's linear-lane ML feature *values* (models that want raw/
    /// monotone-transformed inputs, e.g. LDA). Defaulted no-op.
    fn linear_features(&self, _out: &mut FrameSink) {}
    /// Names for [`ScoreBlock::linear_features`], same order. Defaulted no-op.
    fn linear_feature_names(_out: &mut NameSink) {}
    /// This block's nonlinear-lane ML feature *values* (models that don't need
    /// monotone transforms, e.g. GBM). Defaulted no-op.
    fn nonlinear_features(&self, _out: &mut FrameSink) {}
    /// Names for [`ScoreBlock::nonlinear_features`], same order. Defaulted
    /// no-op.
    fn nonlinear_feature_names(_out: &mut NameSink) {}
    /// Both lanes, linear then nonlinear.
    fn all_features(&self, o: &mut FrameSink) {
        self.linear_features(o);
        self.nonlinear_features(o);
    }
    /// Names for [`ScoreBlock::all_features`], same order.
    fn all_feature_names(o: &mut NameSink)
    where
        Self: Sized,
    {
        Self::linear_feature_names(o);
        Self::nonlinear_feature_names(o);
    }

    /// LEGACY (transition): this block's ML feature *values*, in a fixed
    /// per-block order. Defaulted no-op. See the trait doc for why this stays.
    fn features(&self, _out: &mut FeatSink) {}
}

// ---------------------------------------------------------------------------
// ColSink — row-oriented Parquet column accumulator
// ---------------------------------------------------------------------------

enum ColData {
    F32(Vec<f32>),
    F64(Vec<f64>),
    U8(Vec<u8>),
    U32(Vec<u32>),
    Bool(Vec<bool>),
    Str(Vec<String>),
}

struct Column {
    name: String,
    nullable: bool,
    data: ColData,
}

/// Accumulates Parquet columns one row at a time.
///
/// Each block's `columns(&self, o)` pushes one value per column, in a fixed
/// order per block. On the first row the columns are created (name + dtype +
/// nullability recorded from the typed method); on later rows the cursor walks
/// the existing columns and appends. Scalars are non-nullable; expanded array
/// columns (`f32_array`) are nullable — this preserves the pre-block
/// column name→dtype→nullability set.
#[derive(Default)]
pub struct ColSink {
    cols: Vec<Column>,
    cursor: usize,
}

impl ColSink {
    pub fn new() -> Self {
        Self::default()
    }

    /// Locate the column at the cursor (creating it with an empty `make()`
    /// buffer on the first row), advance the cursor, and hand back its data
    /// buffer for the caller to append one value to. Centralizes the
    /// first-row-vs-append + order-check logic shared by every typed method.
    fn slot(&mut self, name: &str, nullable: bool, make: impl FnOnce() -> ColData) -> &mut ColData {
        let i = self.cursor;
        if i == self.cols.len() {
            self.cols.push(Column {
                name: name.to_string(),
                nullable,
                data: make(),
            });
        } else {
            debug_assert_eq!(self.cols[i].name, name, "column order mismatch");
        }
        self.cursor += 1;
        &mut self.cols[i].data
    }

    fn push_f32(&mut self, name: &str, nullable: bool, v: f32) {
        match self.slot(name, nullable, || ColData::F32(Vec::new())) {
            ColData::F32(vals) => vals.push(v),
            _ => panic!("column `{name}` dtype mismatch"),
        }
    }

    pub fn f32(&mut self, name: &str, v: f32) {
        self.push_f32(name, false, v);
    }

    pub fn f64(&mut self, name: &str, v: f64) {
        match self.slot(name, false, || ColData::F64(Vec::new())) {
            ColData::F64(vals) => vals.push(v),
            _ => panic!("column `{name}` dtype mismatch"),
        }
    }

    pub fn u8(&mut self, name: &str, v: u8) {
        match self.slot(name, false, || ColData::U8(Vec::new())) {
            ColData::U8(vals) => vals.push(v),
            _ => panic!("column `{name}` dtype mismatch"),
        }
    }

    pub fn u32(&mut self, name: &str, v: u32) {
        match self.slot(name, false, || ColData::U32(Vec::new())) {
            ColData::U32(vals) => vals.push(v),
            _ => panic!("column `{name}` dtype mismatch"),
        }
    }

    pub fn bool(&mut self, name: &str, v: bool) {
        match self.slot(name, false, || ColData::Bool(Vec::new())) {
            ColData::Bool(vals) => vals.push(v),
            _ => panic!("column `{name}` dtype mismatch"),
        }
    }

    pub fn str(&mut self, name: &str, v: &str) {
        match self.slot(name, false, || ColData::Str(Vec::new())) {
            ColData::Str(vals) => vals.push(v.to_string()),
            _ => panic!("column `{name}` dtype mismatch"),
        }
    }

    /// Expand a fixed-size `[f32; N]` into `{prefix}_0 .. {prefix}_{N-1}`
    /// nullable columns (matching the pre-block array-column layout).
    pub fn f32_array<const N: usize>(&mut self, prefix: &str, arr: &[f32; N]) {
        for (i, v) in arr.iter().enumerate() {
            self.push_f32(&format!("{prefix}_{i}"), true, *v);
        }
    }

    /// Finish one row: reset the cursor to the first column.
    pub fn end_row(&mut self) {
        self.cursor = 0;
    }

    /// Materialize the accumulated columns into arrow fields + arrays.
    pub fn finish(self) -> (Vec<Field>, Vec<Arc<dyn Array>>) {
        let mut fields = Vec::with_capacity(self.cols.len());
        let mut arrays: Vec<Arc<dyn Array>> = Vec::with_capacity(self.cols.len());
        for c in self.cols {
            let (dtype, arr): (DataType, Arc<dyn Array>) = match c.data {
                ColData::F32(v) => (DataType::Float32, Arc::new(Float32Array::from(v))),
                ColData::F64(v) => (DataType::Float64, Arc::new(Float64Array::from(v))),
                ColData::U8(v) => (DataType::UInt8, Arc::new(UInt8Array::from(v))),
                ColData::U32(v) => (DataType::UInt32, Arc::new(UInt32Array::from(v))),
                ColData::Bool(v) => (DataType::Boolean, Arc::new(BooleanArray::from(v))),
                ColData::Str(v) => (
                    DataType::Utf8,
                    Arc::new(StringArray::from_iter(v.into_iter().map(Some))),
                ),
            };
            fields.push(Field::new(c.name, dtype, c.nullable));
            arrays.push(arr);
        }
        (fields, arrays)
    }
}

// ---------------------------------------------------------------------------
// SchemaSink — Parquet schema-only accumulator (dtype/nullability, no data)
// ---------------------------------------------------------------------------

/// Accumulates Parquet field schema (name, dtype, nullability) without any row
/// data — the schema-only counterpart to [`ColSink`]. Dtype/nullability MUST
/// byte-match `ColSink`'s (scalars non-nullable, expanded array elements
/// nullable); the golden schema test guards this.
#[derive(Default)]
pub struct SchemaSink {
    fields: Vec<Field>,
}

impl SchemaSink {
    pub fn new() -> Self {
        Self::default()
    }

    fn scalar(&mut self, name: &str, dt: DataType) {
        self.fields.push(Field::new(name, dt, false));
    }

    pub fn f32(&mut self, n: &str) {
        self.scalar(n, DataType::Float32);
    }

    pub fn f64(&mut self, n: &str) {
        self.scalar(n, DataType::Float64);
    }

    pub fn u8(&mut self, n: &str) {
        self.scalar(n, DataType::UInt8);
    }

    pub fn u32(&mut self, n: &str) {
        self.scalar(n, DataType::UInt32);
    }

    pub fn bool(&mut self, n: &str) {
        self.scalar(n, DataType::Boolean);
    }

    pub fn str(&mut self, n: &str) {
        self.scalar(n, DataType::Utf8);
    }

    /// Expand a fixed-size `[f32; N]` into `{prefix}_0 .. {prefix}_{N-1}`
    /// nullable fields (matching [`ColSink::f32_array`]'s layout).
    pub fn f32_array(&mut self, prefix: &str, n: usize) {
        for i in 0..n {
            self.fields
                .push(Field::new(format!("{prefix}_{i}"), DataType::Float32, true));
        }
    }

    pub fn into_fields(self) -> Vec<Field> {
        self.fields
    }
}

// ---------------------------------------------------------------------------
// FeatSink — ML feature accumulator
// ---------------------------------------------------------------------------

/// Accumulates ML feature *values* in emission order. Names are not stored here
/// — they are a property of the set, built once by [`NameSink`]. The
/// transform-suffix convention (`_ln1p`, `_round`, …) is fixed and lives only in
/// the `#[feat(..)]` grammar; the value transforms live here so a value and its
/// name-suffix are defined by the same directive.
#[derive(Default)]
pub struct FeatSink {
    vals: Vec<f64>,
}

impl FeatSink {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&mut self, v: f64) {
        self.vals.push(v);
    }

    /// Push one raw value per array element (`f32` widened to `f64`). Shared by
    /// the array blocks ([`ion_errors`], [`relative_intensities`]).
    pub fn push_slice(&mut self, vals: &[f32]) {
        self.vals.extend(vals.iter().map(|v| *v as f64));
    }

    pub fn push_ln1p(&mut self, x: f64) {
        self.vals.push(x.ln_1p());
    }

    pub fn push_log2(&mut self, x: f64) {
        self.vals.push(x.log2());
    }

    pub fn push_round(&mut self, x: f64) {
        self.vals.push(x.round());
    }

    /// Magnitude fold (`|x|`, NaN preserved). Turns a center-is-better signed
    /// feature (small error good, both tails bad) into a monotone one a linear
    /// discriminant can weight; inert for trees (monotone of the raw value).
    pub fn push_abs(&mut self, x: f64) {
        self.vals.push(x.abs());
    }

    /// Missingness indicator (`1.0` if the source value is non-finite, else
    /// `0.0`). Pairs with a value transform to encode not-missing-at-random
    /// structure a mean-impute would erase; the value column self-imputes to
    /// the mean model-side, this preserves the "was missing" bit.
    pub fn push_isna(&mut self, x: f64) {
        self.vals.push(if x.is_finite() { 0.0 } else { 1.0 });
    }

    /// `push_abs` for each element of an array field.
    pub fn push_slice_abs(&mut self, vals: &[f32]) {
        self.vals.extend(vals.iter().map(|v| (*v as f64).abs()));
    }

    /// `push_isna` for each element of an array field.
    pub fn push_slice_isna(&mut self, vals: &[f32]) {
        self.vals
            .extend(vals.iter().map(|v| if v.is_finite() { 0.0 } else { 1.0 }));
    }

    /// The accumulated values, in emission order.
    pub fn into_values(self) -> Vec<f64> {
        self.vals
    }
}

// ---------------------------------------------------------------------------
// NameSink — set-level ML feature-name accumulator
// ---------------------------------------------------------------------------

/// Builds the ML feature-name list ONCE for a whole fit (a property of the
/// feature set, not of any record). Names are `Arc<str>` so array families can
/// generate them lazily ([`NameSink::push_indexed`]) instead of const tables,
/// and so callers can share the list cheaply.
#[derive(Default)]
pub struct NameSink {
    names: Vec<Arc<str>>,
}

impl NameSink {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&mut self, name: &str) {
        self.names.push(Arc::from(name));
    }

    /// The array-family fan-out: `{prefix}_0 .. {prefix}_{n-1}` (mirrors
    /// [`ColSink::f32_array`]'s column naming).
    pub fn push_indexed(&mut self, prefix: &str, n: usize) {
        for i in 0..n {
            self.names.push(Arc::from(format!("{prefix}_{i}")));
        }
    }

    /// [`NameSink::push_indexed`] with a trailing transform suffix, so an
    /// array family's `abs`/`isna` companions read `{prefix}_{i}_abs` — the
    /// same `{name}{suffix}` convention the scalar macro uses.
    pub fn push_indexed_suffixed(&mut self, prefix: &str, n: usize, suffix: &str) {
        for i in 0..n {
            self.names.push(Arc::from(format!("{prefix}_{i}{suffix}")));
        }
    }

    /// The accumulated names, in emission order.
    pub fn into_names(self) -> Vec<Arc<str>> {
        self.names
    }
}

// ---------------------------------------------------------------------------
// BlockFixture — fixed sample constants for macro-generated `sample()`
// ---------------------------------------------------------------------------

/// Supplies a fixed constant per field type for a block's generated `sample()`.
/// Sample *values* are arbitrary but finite and non-zero (so ratio-derived
/// features stay finite in tests).
pub trait BlockFixture {
    fn fixture() -> Self;
}

impl BlockFixture for f32 {
    fn fixture() -> Self {
        0.5
    }
}
impl BlockFixture for f64 {
    fn fixture() -> Self {
        0.5
    }
}
impl BlockFixture for u8 {
    fn fixture() -> Self {
        1
    }
}
impl BlockFixture for u32 {
    fn fixture() -> Self {
        1
    }
}
impl BlockFixture for bool {
    fn fixture() -> Self {
        true
    }
}
impl<const N: usize> BlockFixture for [f32; N] {
    fn fixture() -> Self {
        [0.5; N]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn schema_sink_matches_colsink_dtypes() {
        let mut ss = SchemaSink::new();
        ss.f32("a");
        ss.f32_array("arr", 3);
        let fields = ss.into_fields();
        assert_eq!(fields[0].data_type(), &DataType::Float32);
        assert!(!fields[0].is_nullable());
        assert_eq!(fields[1].name(), "arr_0");
        assert!(fields[1].is_nullable());
        assert_eq!(fields.len(), 4);
    }
}
